var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。`,ENG:`that you'll be with her, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called her to your office. She said she'd be here soon.`,TWN:`做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`INGRID_STREGA_NULL_NULL`,text:{KOREA:`종신계약?`,JPN:`終身契約？`,ENG:`A lifetime contract?`,TWN:`終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`INGRID_STREGA_NULL_NULL`,text:{KOREA:`아무튼 이 회사에서 계속 싸우면 된다는 거지? 나쁠 것 없네.`,JPN:`この会社で戦い続けてればいいってことでしょ？
悪い話じゃなさそうだね。`,ENG:`This means you just want me to keep fighting for your company, right? Sure, why not?`,TWN:`總之，意思就是在這家公司繼續戰鬥吧？沒什麼不好的嘛。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`INGRID_STREGA_NULL_NULL`,text:{KOREA:`사장님과 같이 다니면 새로운 강적들을 많이 만날 수 있을 거 아냐?`,JPN:`社長と一緒なら、これからも新しい強敵達にたくさん会えるよね？`,ENG:`If I stay with you, I'll have plenty of chances to meet formidable enemies, right?`,TWN:`和老闆在一起的話，不是能遇到很多新的強敵嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`INGRID_STREGA_NULL_NULL`,text:{KOREA:`계약서? 그런 귀찮은 거 대신 주먹박치기는 어때?`,JPN:`契約書？
そんなややこしいものより、拳を突き合わせて誓ったらどう？`,ENG:`A contract? Can't we just fist-bump instead?`,TWN:`契約書？我們不如用擊拳來代替這種麻煩的東西，怎麼樣？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`INGRID_STREGA_NULL_NULL`,text:{KOREA:`......흐음, 꼭 필요하다면야, 읽는 시늉은 해볼게.`,JPN:`……ふーん、どうしても必要って言うなら、とりあえず読むふりくらいはしておこうかな。`,ENG:`Hmm, if it's really necessary, then I guess I can at least try to read it.`,TWN:`……嗯，如果一定要這麼做，我會裝個樣子看一下契約的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`INGRID_STREGA_NULL_NULL`,text:{KOREA:`대신, 지금보다 더 많이 싸우게 해줘야 돼. 알겠지?`,JPN:`その代わり、今までよりもっとたくさん戦わせてよね。わかった？`,ENG:`But you'd better provide me with more chances to fight. Got it?`,TWN:`但是，你得讓我有更多架可以打，知道了吧？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`INGRID_STREGA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};